def person(name, age, gender='male'):
    print(f"名前：{name}、年齢：{age}、性別：{gender}")

①、②に当てはまる選択肢を選択してください。

def test(name, ①, ②):
  print(name)
  for kw in a:
    print(a[kw])
  for arg in b:
    print(arg)

test("Yamada", "特技は水泳", "趣味は読書", job="デザイナー", age=18)

# 出力: Yamada / デザイナー / 18 / 特技は水泳 / 趣味は読書
